import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;

class Logger {
  static void logHttpRequest(http.Request request) {
    debugPrint('HTTP Request: ${request.method} ${request.url}');
    debugPrint('Headers: ${request.headers}');
    if (request.body.isNotEmpty) {
      debugPrint('Body: ${request.body}');
    }
  }

  static void logHttpResponse(http.Response response) {
    debugPrint('HTTP Response: ${response.statusCode}');
    debugPrint('Response Body: ${response.body}');
  }

  static void logDatabaseOperation(String operation, String details) {
    debugPrint('Database Operation: $operation');
    debugPrint('Details: $details');
  }

  static void logAuthFlow(String action, {String? token}) {
    debugPrint('Auth Action: $action');
    if (token != null) {
      debugPrint('Token: $token');
    }
  }

  static void logUserInteraction(String interaction) {
    debugPrint('User Interaction: $interaction');
  }
}

class ApiService {
  Future<void> fetchData() async {
    final request = http.Request('GET', Uri.parse('https://api.example.com/data'));
    Logger.logHttpRequest(request);
    
    final response = await http.Response('{"data": "sample"}', 200);
    Logger.logHttpResponse(response);
  }
}

class DatabaseService {
  void performOperation(String operation) {
    Logger.logDatabaseOperation(operation, 'Performed operation on the database');
  }
}

class AuthService {
  void login(String username, String password) {
    Logger.logAuthFlow('Login Attempt', token: 'sample_token'); // Redacted token
  }
}

